132	func smartRouteUnavailableReport(b *bead.Bead, minPower, maxPower int, cause error) agent.ExecuteBeadReport {
133		beadID := ""
134		if b != nil {
135			beadID = b.ID
136		}
137		detail := fmt.Sprintf("smart retry route unavailable: no viable routing candidate satisfies requested MinPower %d", minPower)
138		if maxPower > 0 {
139			detail += fmt.Sprintf(" and MaxPower %d", maxPower)
140		}
141		if cause != nil {
142			detail += ": " + cause.Error()
143		}
144		return agent.ExecuteBeadReport{
145			BeadID:        beadID,
146			Status:        agent.ExecuteBeadStatusExecutionFailed,
147			Detail:        detail,
148			OutcomeReason: agent.FailureModeNoViableProvider,
149		}
150	}
