152	func runEscalatingSingleTierAttempts(
153		ctx context.Context,
154		initialMinPower int,
155		ladder escalationFloorFinder,
156		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
157		recordAttempt func(agent.ExecuteBeadReport),
158		perBeadTracker *policyescalation.PerBeadCostTracker,
159	) (agent.ExecuteBeadReport, error) {
160		minPower := initialMinPower
161		for {
162			report, err := attempt(ctx, minPower)
163			if recordAttempt != nil && report.BeadID != "" {
164				recordAttempt(report)
165			}
166			if perBeadTracker != nil {
167				perBeadTracker.Add(report.Harness, report.CostUSD)
168			}
169			if err != nil {
170				return report, err
171			}
172			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
173				return report, nil
174			}
175			// Check per-bead budget before escalating to the next tier.
176			if perBeadTracker != nil {
177				if detail, tripped := perBeadTracker.Tripped(); tripped {
178					report.Status = agent.ExecuteBeadStatusExecutionFailed
179					report.Detail = detail
180					report.CostUSD = perBeadTracker.Spent() // total for this bead
181					return report, nil
182				}
183			}
184			basis := minPower
185			if report.ActualPower > 0 {
186				basis = report.ActualPower
187			}
188			nextPower, nextErr := nextEscalationFloor(ladder, basis)
189			if nextErr != nil {
190				return report, nil
191			}
192			minPower = nextPower
193		}
194	}
