1890	func formatAttemptRouteEconomics(attempt agent.ExecuteBeadReport) string {
1891		if attempt.Harness == "" && attempt.Provider == "" && attempt.Model == "" {
1892			return ""
1893		}
1894		parts := []string{}
1895		if attempt.Harness != "" {
1896			parts = append(parts, "harness="+attempt.Harness)
1897		}
1898		if attempt.Provider != "" {
1899			parts = append(parts, "provider="+attempt.Provider)
1900		}
1901		if attempt.Model != "" {
1902			parts = append(parts, "model="+attempt.Model)
1903		}
1904		power := attempt.PredictedPower
1905		if power == 0 {
1906			power = attempt.ActualPower
1907		}
1908		if power > 0 {
1909			parts = append(parts, fmt.Sprintf("power=%d", power))
1910		}
1911		if attempt.PredictedSpeedTPS > 0 {
1912			parts = append(parts, fmt.Sprintf("speed=%.1f tok/s", attempt.PredictedSpeedTPS))
1913		}
1914		if attempt.PredictedCostUSDPer1kTokens > 0 {
1915			cost := fmt.Sprintf("cost=$%.6f/1k tok", attempt.PredictedCostUSDPer1kTokens)
1916			if attempt.PredictedCostSource != "" {
1917				cost += " source=" + attempt.PredictedCostSource
1918			}
1919			parts = append(parts, cost)
1920		} else if attempt.PredictedCostSource != "" {
1921			parts = append(parts, "cost_source="+attempt.PredictedCostSource)
1922		}
1923		return strings.Join(parts, " ")
1924	}
