1927		if asJSON {
1928			payload := struct {
1929				ProjectRoot string `json:"project_root"`
1930				*agent.ExecuteBeadLoopResult
1931			}{
1932				ProjectRoot:           projectRoot,
1933				ExecuteBeadLoopResult: result,
1934			}
1935			enc := json.NewEncoder(w)
1936			enc.SetIndent("", "  ")
1937			return enc.Encode(payload)
1938		}
1939	
1940		if result.NoReadyWork && result.Attempts == 0 {
1941			writeNoReadyWorkSummary(w, projectRoot, result.NoReadyWorkDetail)
1942			writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
1943			return nil
1944		}
1945	
1946		fmt.Fprintf(w, "\nproject: %s\n", projectRoot)
1947		writeWorkTerminalSummary(w, result)
1948		if result.Failures > 0 {
1949			fmt.Fprintf(w, "\nfailed:\n")
1950			for _, attempt := range result.Results {
1951				if attempt.Status != "success" {
1952					fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
1953					if attempt.PreserveRef != "" {
1954						fmt.Fprintf(w, " (preserved)")
1955					}
1956					fmt.Fprintln(w)
1957				}
1958			}
1959		}
1960		if result.NoReadyWork {
1961			fmt.Fprintln(w)
1962			writeNoReadyWorkSummary(w, "", result.NoReadyWorkDetail)
1963			writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
1964		}
1965		return nil
1966	}
