1968	func writeWorkTerminalSummary(w io.Writer, result *agent.ExecuteBeadLoopResult) {
1969		closed, changed, alreadySatisfied := countWorkTerminalOutcomes(result)
1970		fmt.Fprintf(w, "worker exited: %s\n", workExitSummary(result))
1971		fmt.Fprintf(w, "attempts: %d  |  closed: %d  |  changed: %d  |  already-satisfied: %d  |  failures: %d\n",
1972			result.Attempts, closed, changed, alreadySatisfied, result.Failures)
1973	}
1974	
1975	func countWorkTerminalOutcomes(result *agent.ExecuteBeadLoopResult) (closed, changed, alreadySatisfied int) {
1976		for _, attempt := range result.Results {
1977			switch attempt.Status {
1978			case agent.ExecuteBeadStatusSuccess:
1979				closed++
1980				changed++
1981			case agent.ExecuteBeadStatusAlreadySatisfied:
1982				closed++
1983				alreadySatisfied++
1984			}
1985		}
1986		if closed == 0 && result.Successes > 0 {
1987			closed = result.Successes
1988		}
1989		return closed, changed, alreadySatisfied
1990	}
1991	
1992	func workExitSummary(result *agent.ExecuteBeadLoopResult) string {
1993		switch result.ExitReason {
1994		case "drained":
1995			return "drained current execution-ready queue"
1996		case "once_complete":
1997			return "once complete"
1998		case "budget":
1999			return "budget reached"
2000		case "no_progress":
2001			return "no-progress policy stopped work"
2002		case "blocked":
2003			return "blocked waiting for external action"
2004		case "sigint", "sigterm", "context_cancelled":
2005			return "stopped by signal"
2006		case "fatal_config":
2007			return "fatal configuration error"
2008		case "preflight_failed":
2009			return "preflight failed"
2010		case "resource_exhausted":
2011			return "resource exhausted"
2012		case "routing_unavailable":
