89	// numericTierFloorHint returns the numeric MinPower floor stored by the
90	// no-changes smart-retry path, which advances one ladder step at a time.
91	// Tier-name string hints (from the review-triage path) are not matched here.
92	func numericTierFloorHint(b *bead.Bead) (int, bool) {
93		if b == nil || b.Extra == nil {
94			return 0, false
95		}
96		raw, ok := b.Extra[agent.TriageTierHintKey]
97		if !ok {
98			return 0, false
99		}
100		switch v := raw.(type) {
101		case int:
102			return v, v > 0
103		case int64:
104			return int(v), int(v) > 0
105		case float64:
106			return int(v), int(v) > 0
107		default:
108			return 0, false
109		}
110	}
111	
112	func triageTierHint(b *bead.Bead) (policyescalation.ModelTier, bool) {
113		if b == nil || b.Extra == nil {
114			return "", false
115		}
116		raw, ok := b.Extra[agent.TriageTierHintKey]
117		if !ok {
118			return "", false
119		}
120		switch strings.ToLower(strings.TrimSpace(fmt.Sprint(raw))) {
121		case string(policyescalation.TierSmart):
122			return policyescalation.TierSmart, true
123		case string(policyescalation.TierStandard):
124			return policyescalation.TierStandard, true
125		case string(policyescalation.TierCheap):
126			return policyescalation.TierCheap, true
127		default:
128			return "", false
129		}
130	}
