178		case strings.Contains(field, "provider"):
179			message = fmt.Sprintf("bead metadata contains %s; durable provider pins are not allowed. Use ddx try %s --provider ... for one-off debugging.", pin, beadID)
180		case strings.Contains(field, "model"):
181			message = fmt.Sprintf("bead metadata contains %s; durable model pins are not allowed. Use ddx try %s --model ... for one-off debugging.", pin, beadID)
182		default:
183			message = fmt.Sprintf("bead metadata contains %s; durable route pins are not allowed.", pin)
184		}
185		return ExecutionHintFinding{
186			Field:   field,
187			Value:   pin,
188			Message: message,
189		}
190	}
